# ML potential tests
# Run after generating reference data:
#   python test/torchani_reference.py --skip-protein
# Then:
#   julia --project -e 'using Molly, Lux, HDF5, KernelAbstractions; include("test/ml_potentials.jl")'
# KernelAbstractions is required: the ANI forces path (AtomsCalculators.forces! →
# compute_ani_forces_ka) is the KA analytic backward pass (no Enzyme/finite-difference paths).

using Molly
using Lux, HDF5, KernelAbstractions
using StaticArrays, Unitful, LinearAlgebra
using Test, JSON3, Random

# Path to reference data generated by test/torchani_reference.py
const REF_DIR = joinpath(@__DIR__, "..", "data", "ani_reference")

# ============================================================================
# Test 1: AEV validation against TorchANI for N₂ dimer
# ============================================================================

@testset "ANI AEV: N₂ dimer matches TorchANI reference" begin
    ref_path = joinpath(REF_DIR, "n2_aevs.json")
    if !isfile(ref_path)
        @warn "Reference AEV file not found at $ref_path — run test/torchani_reference.py first"
        @test_broken false
    else
        ref = JSON3.read(read(ref_path, String))
        aev_ref = Float32.(reduce(hcat, ref.aevs)')   # (2, 1008) reference

        # Build the same N₂ dimer system
        # TorchANI ANI-2x default AEV parameters (from torchani source)
        # These must match what torchani_reference.py exports in ani2x.h5
        h5_path = joinpath(REF_DIR, "ani2x.h5")
        if !isfile(h5_path)
            @warn "ani2x.h5 not found at $h5_path — run test/torchani_reference.py first"
            @test_broken false
        else
            pot = ANIPotential(h5_path)
            n_species = length(pot.species_map)

            # N₂ dimer: 2 N atoms, bond length 1.1 Å, no PBC (infinite box)
            coords = [SVector(0.0f0, 0.0f0, 0.0f0), SVector(1.1f0, 0.0f0, 0.0f0)]
            # N is species index for N in ANI-2x species map
            species_idx = [pot.species_map["N"], pot.species_map["N"]]

            # Infinite boundary — use CubicBoundary with very large box
            boundary = CubicBoundary(1000.0f0)

            aevs = Molly.compute_aevs(coords, species_idx, nothing, boundary,
                                      pot.aev_params, n_species)

            @test size(aevs) == size(aev_ref)
            @test aevs ≈ aev_ref atol=1e-4
            println("Max AEV deviation: ", maximum(abs.(aevs .- aev_ref)))
        end
    end
end

# ============================================================================
# Test 2: ANIPotential loads from HDF5 with correct structure
# ============================================================================

@testset "ANIPotential: loads from HDF5" begin
    h5_path = joinpath(REF_DIR, "ani2x.h5")
    if !isfile(h5_path)
        @warn "ani2x.h5 not found — run test/torchani_reference.py first"
        @test_broken false
    else
        pot = ANIPotential(h5_path)

        @test length(pot.species_map) == 7
        for elem in ["H", "C", "N", "O", "S", "F", "Cl"]
            @test haskey(pot.species_map, elem)
        end

        # Check AEV params are finite and positive where expected
        @test pot.aev_params.r_c_R > 0
        @test pot.aev_params.r_c_A > 0
        @test pot.cutoff == max(pot.aev_params.r_c_R, pot.aev_params.r_c_A)
        @test !isempty(pot.aev_params.η_R)
        @test !isempty(pot.aev_params.r_s_R)
        @test !isempty(pot.aev_params.η_A)
        @test !isempty(pot.aev_params.r_s_A)
        @test pot.aev_params.ζ > 0
        # AEV length: n_species × n_η_R × n_ShfR + n_pairs × n_η_A × n_ShfZ × n_ShfA
        n_sp   = length(pot.species_map)
        n_pair = n_sp * (n_sp + 1) ÷ 2
        aev_len = n_sp * length(pot.aev_params.η_R) * length(pot.aev_params.r_s_R) +
                  n_pair * length(pot.aev_params.η_A) * length(pot.aev_params.r_s_A) * length(pot.aev_params.θ_s)
        @test aev_len == 1008
        println("ANI-2x: r_c_R=", pot.aev_params.r_c_R, " Å, AEV length = ", aev_len)
    end
end

# ============================================================================
# Test 3: Lux forward pass shape for each element sub-network
# ============================================================================

@testset "ANIPotential: forward pass shape" begin
    h5_path = joinpath(REF_DIR, "ani2x.h5")
    if !isfile(h5_path)
        @warn "ani2x.h5 not found — run test/torchani_reference.py first"
        @test_broken false
    else
        pot = ANIPotential(h5_path)
        n_species  = length(pot.species_map)
        n_pairs    = n_species * (n_species + 1) ÷ 2
        n_rad_per  = length(pot.aev_params.η_R) * length(pot.aev_params.r_s_R)    # EtaR × ShfR
        n_ang_per  = length(pot.aev_params.η_A) * length(pot.aev_params.r_s_A) * length(pot.aev_params.θ_s)
        aev_len    = n_species * n_rad_per + n_pairs * n_ang_per   # should be 1008

        # Use the first ensemble member's parameters for shape check
        ps1 = pot.ps_vec[1]
        st1 = pot.st_vec[1]
        for elem in keys(pot.species_map)
            sym = Symbol(elem)
            model = getfield(pot.model, sym)
            ps    = getfield(ps1, sym)
            st    = getfield(st1, sym)
            x     = randn(Float32, aev_len, 1)   # (aev_length, batch=1)
            y, _  = Lux.apply(model, x, ps, st)
            @test size(y) == (1, 1)
        end
        println("All element sub-networks produce shape (1,1) output ✓")
    end
end

# ============================================================================
# Test 4: Energy sign-check for N₂ dimer (quick sanity, no reference needed)
# ============================================================================

@testset "ANIPotential: N₂ dimer energy sign" begin
    h5_path = joinpath(REF_DIR, "ani2x.h5")
    if !isfile(h5_path)
        @warn "ani2x.h5 not found — skipping"
        @test_broken false
    else
        pot = ANIPotential(h5_path)

        atoms = [Atom(mass=14.0u"u"), Atom(mass=14.0u"u")]
        coords = [SVector(0.0, 0.0, 0.0)u"Å", SVector(1.1, 0.0, 0.0)u"Å"]
        atoms_data = [AtomData(element="N"), AtomData(element="N")]
        boundary = CubicBoundary(100.0u"Å")

        sys = System(
            atoms      = atoms,
            coords     = coords,
            boundary   = boundary,
            atoms_data = atoms_data,
            general_inters = (ani=pot,),
            force_units    = u"eV/Å",
            energy_units   = u"eV",
        )

        E = potential_energy(sys)
        @test E < 0u"eV"   # binding energy should be negative
        println("N₂ dimer energy: ", round(typeof(E), E, sigdigits=8))

        # Cross-check against JSON reference if available
        ref_path = joinpath(REF_DIR, "n2_dimer_ani2x.json")
        if isfile(ref_path)
            ref = JSON3.read(read(ref_path, String))
            E_ref = Float64(ref.energy_eV)u"eV"
            @test isapprox(E, E_ref; rtol=1e-3)
            println("TorchANI reference: ", round(typeof(E_ref), E_ref, sigdigits=8))
        end
    end
end

# ============================================================================
# Test 5: Force validation against TorchANI reference for N₂ dimer
# ============================================================================

@testset "ANIPotential: N₂ dimer forces match TorchANI" begin
    ref_path = joinpath(REF_DIR, "n2_dimer_ani2x.json")
    h5_path  = joinpath(REF_DIR, "ani2x.h5")
    if !isfile(ref_path) || !isfile(h5_path)
        @warn "Reference files not found — run test/torchani_reference.py first"
        @test_broken false
    else
        ref = JSON3.read(read(ref_path, String))
        # forces_eV_per_A is a 2×3 array: [[fx1,fy1,fz1], [fx2,fy2,fz2]]
        f_ref = [SVector{3,Float64}(row...) for row in ref.forces_eV_per_A]

        pot = ANIPotential(h5_path)
        atoms      = [Atom(mass=14.0u"u"), Atom(mass=14.0u"u")]
        coords     = [SVector(0.0, 0.0, 0.0)u"Å", SVector(1.1, 0.0, 0.0)u"Å"]
        atoms_data = [AtomData(element="N"), AtomData(element="N")]
        boundary   = CubicBoundary(100.0u"Å")

        sys = System(
            atoms          = atoms,
            coords         = coords,
            boundary       = boundary,
            atoms_data     = atoms_data,
            general_inters = (ani=pot,),
            force_units    = u"eV/Å",
            energy_units   = u"eV",
        )

        fs = forces(sys)
        # Strip units for comparison
        fs_val = [ustrip.(u"eV/Å", f) for f in fs]

        for i in 1:2
            @test isapprox(fs_val[i], f_ref[i]; atol=1e-3)
        end
        # Newton's 3rd law: forces must sum to zero
        @test isapprox(fs_val[1] + fs_val[2], zeros(3); atol=1e-10)

        println("Force on N1: ", round.(fs_val[1], sigdigits=6), " eV/Å")
        println("Force on N2: ", round.(fs_val[2], sigdigits=6), " eV/Å")
        println("Max force deviation: ",
            maximum(abs.(reduce(vcat, fs_val) .- reduce(vcat, f_ref))), " eV/Å")
    end
end

# ============================================================================
# Test 6: Ensemble averaging — all 8 ANI-2x members loaded and averaged
# ============================================================================

@testset "ANIPotential: ensemble averaging" begin
    h5_path = joinpath(REF_DIR, "ani2x.h5")
    if !isfile(h5_path)
        @warn "ani2x.h5 not found — skipping"
        @test_broken false
    else
        pot_full = ANIPotential(h5_path)                      # all ensemble members
        pot_0    = ANIPotential(h5_path; ensemble_idx=0)      # single member

        @test length(pot_full.ps_vec) == 8
        @test length(pot_full.st_vec) == 8
        @test length(pot_0.ps_vec)    == 1

        atoms      = [Atom(mass=14.0u"u"), Atom(mass=14.0u"u")]
        coords     = [SVector(0.0, 0.0, 0.0)u"Å", SVector(1.1, 0.0, 0.0)u"Å"]
        atoms_data = [AtomData(element="N"), AtomData(element="N")]
        boundary   = CubicBoundary(100.0u"Å")

        sys_full = System(
            atoms=atoms, coords=coords, boundary=boundary, atoms_data=atoms_data,
            general_inters=(ani=pot_full,), force_units=u"eV/Å", energy_units=u"eV",
        )
        sys_0 = System(
            atoms=atoms, coords=coords, boundary=boundary, atoms_data=atoms_data,
            general_inters=(ani=pot_0,), force_units=u"eV/Å", energy_units=u"eV",
        )

        E_full = potential_energy(sys_full)
        E_0    = potential_energy(sys_0)

        @test E_full < 0u"eV"
        # Ensemble mean and single member should agree within ~0.1 eV
        @test isapprox(ustrip(u"eV", E_full), ustrip(u"eV", E_0); atol=0.1)
        println("Ensemble-averaged energy: ", round(typeof(E_full), E_full, sigdigits=8))
        println("Single-member  energy:    ", round(typeof(E_0),    E_0,    sigdigits=8))
    end
end

# ============================================================================
# Test 7: Neighbor-list AEV consistency (O(N²) path vs DistanceNeighborFinder)
# ============================================================================

@testset "ANIPotential: neighbor-list path consistency" begin
    h5_path = joinpath(REF_DIR, "ani2x.h5")
    if !isfile(h5_path)
        @warn "ani2x.h5 not found — skipping"
        @test_broken false
    else
        # Single member for speed; cutoff is the larger of r_c_R and r_c_A
        pot     = ANIPotential(h5_path; ensemble_idx=0)
        n_atoms = 2
        atoms      = [Atom(mass=14.0u"u"), Atom(mass=14.0u"u")]
        coords     = [SVector(0.0, 0.0, 0.0)u"Å", SVector(1.1, 0.0, 0.0)u"Å"]
        atoms_data = [AtomData(element="N"), AtomData(element="N")]
        boundary   = CubicBoundary(100.0u"Å")

        # System with DistanceNeighborFinder → uses neighbor-list AEV path
        nf = DistanceNeighborFinder(
            eligible    = trues(n_atoms, n_atoms),
            dist_cutoff = (Float64(pot.cutoff) + 1.0) * u"Å",
        )
        sys_nbr = System(
            atoms=atoms, coords=coords, boundary=boundary, atoms_data=atoms_data,
            general_inters=(ani=pot,), force_units=u"eV/Å", energy_units=u"eV",
            neighbor_finder=nf,
        )
        # System with no neighbor finder → uses O(N²) AEV path
        sys_full = System(
            atoms=atoms, coords=coords, boundary=boundary, atoms_data=atoms_data,
            general_inters=(ani=pot,), force_units=u"eV/Å", energy_units=u"eV",
        )

        E_nbr  = potential_energy(sys_nbr)   # neighbor-list path
        E_full = potential_energy(sys_full)  # O(N²) fallback path

        @test isapprox(ustrip(u"eV", E_nbr), ustrip(u"eV", E_full); atol=1e-6)
        println("Energy via neighbor list: ", E_nbr)
        println("Energy via O(N²) path:   ", E_full)
        println("Δ = ", abs(ustrip(u"eV", E_nbr) - ustrip(u"eV", E_full)), " eV")
    end
end

# ============================================================================
# Test 8: End-to-end MD simulation — NVE energy conservation for N₂ dimer
# ============================================================================

@testset "ANIPotential: end-to-end MD simulation (NVE)" begin
    h5_path = joinpath(REF_DIR, "ani2x.h5")
    if !isfile(h5_path)
        @warn "ani2x.h5 not found — skipping"
        @test_broken false
    else
        pot = ANIPotential(h5_path; ensemble_idx=0)  # single member for speed

        atoms      = [Atom(mass=14.0u"u"), Atom(mass=14.0u"u")]
        coords     = [SVector(0.0, 0.0, 0.0)u"Å", SVector(1.1, 0.0, 0.0)u"Å"]
        atoms_data = [AtomData(element="N"), AtomData(element="N")]
        boundary   = CubicBoundary(100.0u"Å")

        sys = System(
            atoms          = atoms,
            coords         = coords,
            boundary       = boundary,
            atoms_data     = atoms_data,
            general_inters = (ani=pot,),
            force_units    = u"eV/Å",
            energy_units   = u"eV",
        )

        # Assign random velocities at 300 K (seeded for reproducibility)
        random_velocities!(sys, 300.0u"K"; rng=MersenneTwister(42))

        E0     = total_energy(sys)
        simulate!(sys, VelocityVerlet(dt=0.1u"fs"), 50)
        E_final = total_energy(sys)

        # NVE: total energy should be approximately conserved
        drift = abs(ustrip(u"eV", E_final - E0)) / abs(ustrip(u"eV", E0))
        @test drift < 0.05   # < 5% relative drift over 50 steps at 0.1 fs
        @test norm(sys.coords[1] - sys.coords[2]) > 0.5u"Å"  # no explosion
        println("Initial total energy: ", round(typeof(E0),      E0,      sigdigits=8))
        println("Final   total energy: ", round(typeof(E_final), E_final, sigdigits=8))
        println("Relative energy drift: ", round(drift * 100, sigdigits=3), " %")
    end
end

