            @test isapprox(E_ref, E_ka; atol=0.05)   # ≤ ~5e-4 eV/atom (Float32 AEV gap)
            println("Test17: E_ref=", E_ref, " E_ka=", E_ka, " diff=", abs(E_ref - E_ka))
        end
    end
end

# ============================================================================
# Test 18: KA kernels apply the minimum-image convention via Molly.vector, for both
#          CubicBoundary and TriclinicBoundary. Two water molecules are placed near
#          opposite faces of a small periodic box so they are neighbours only through
#          the boundary. The KA kernels (CPU backend) must match the CPU compute_aevs
#          (which already uses vector), and the boundary must change the AEV vs an
#          infinite box. Runs on the KA CPU backend; the same kernels run on Metal/CUDA.
# ============================================================================
if isdefined(@__MODULE__, :KernelAbstractions) || @isdefined(KernelAbstractions)
    @testset "ANIPotential: KA kernels apply minimum-image (Cubic + Triclinic)" begin
        h5_path = joinpath(REF_DIR, "ani2x.h5")
        if !isfile(h5_path)
            @warn "ani2x.h5 not found — skipping"
            @test_broken false
        else
            pot  = ANIPotential(h5_path; ensemble_idx=0)
            p    = pot.aev_params
            n_sp = length(pot.species_map)
            cpu  = KernelAbstractions.CPU()

            L = 6.0
            coords = SVector{3,Float64}[
                SVector(0.30,3.0,3.0), SVector(0.30,3.0,3.96), SVector(1.20,3.0,3.0),
                SVector(5.70,3.0,3.0), SVector(5.70,3.0,3.96), SVector(4.80,3.0,3.0)]
            species = [pot.species_map[e] for e in ["O","H","H","O","H","H"]]
            n = length(coords)
            cub = CubicBoundary(L)
            tri = TriclinicBoundary(SVector(SVector(L,0.0,0.0), SVector(0.0,L,0.0),
                                            SVector(0.0,0.0,L)))

            for (name, bdy) in (("Cubic", cub), ("Triclinic", tri))
                ref = Molly.compute_aevs(coords, species, nothing, bdy, p, n_sp)
                ka  = Molly.compute_aevs_ka(coords, species, p, n_sp; backend=cpu, boundary=bdy)
                @test ka ≈ ref atol=1e-4
                println("Test18 $name: KA-vs-CPU max dev = ", maximum(abs.(ka .- ref)))
            end

            # The boundary must actually change the AEV vs an infinite (non-periodic) box.
            ka_box = Molly.compute_aevs_ka(coords, species, p, n_sp; backend=cpu, boundary=cub)
            ka_inf = Molly.compute_aevs_ka(coords, species, p, n_sp; backend=cpu)
            @test maximum(abs.(ka_box .- ka_inf)) > 0.1
        end
    end
end

# ============================================================================
# Test 19: on-device ANI forces (the single forces path) — GPU AEV + NN VJP (∂E/∂G) +
#          backward radial/angular kernels (∂E/∂r). Runs on the KA CPU backend (no GPU
#          needed); the same kernels run on Metal/CUDA. Validated three ways on N₂ and H₂O:
#          (1) vs the TorchANI reference (canonical), (2) a finite-difference cross-check on
#          the energy (independent, replaces the former Enzyme cross-check), and (3) that
#          forces(sys) (the AtomsCalculators path) matches the direct call; plus ΣF ≈ 0.
# ============================================================================
if @isdefined(KernelAbstractions)
    @testset "ANIPotential: on-device forces (compute_ani_forces_ka, CPU backend)" begin
        h5_path = joinpath(REF_DIR, "ani2x.h5")
        if !isfile(h5_path)
            @warn "ani2x.h5 not found — skipping"
            @test_broken false
        else
            pot  = ANIPotential(h5_path)          # full ensemble (matches TorchANI reference)
            n_sp = length(pot.species_map)
            cpu  = KernelAbstractions.CPU()
            bx   = CubicBoundary(100.0u"Å")
            M = Dict("H"=>1.008, "C"=>12.011, "N"=>14.007, "O"=>15.999,
                     "F"=>18.998, "S"=>32.06, "Cl"=>35.45)

            for jf in ("n2_dimer_ani2x.json", "water_ani2x.json")
                ref   = JSON3.read(read(joinpath(REF_DIR, jf), String))
                elems = String.(ref.species)
                crd   = [SVector{3,Float64}(r...) for r in ref.coordinates_A]
                f_ref = [SVector{3,Float64}(r...) for r in ref.forces_eV_per_A]
                sp    = [pot.species_map[e] for e in elems]

                sys = System(atoms=[Atom(mass=M[e]*u"u") for e in elems],
                    coords=[c*u"Å" for c in crd], boundary=bx,
                    atoms_data=[AtomData(element=e) for e in elems],
                    general_inters=(ani=pot,), force_units=u"eV/Å", energy_units=u"eV")

                f_ka  = Molly.compute_ani_forces_ka(crd, sp, pot, n_sp; backend=cpu, boundary=bx)
                f_sys = [ustrip.(u"eV/Å", f) for f in forces(sys)]   # AtomsCalculators path

                # Independent finite-difference forces from the energy: F = -dE/dr.
                E(c) = ustrip(u"eV", potential_energy(System(sys; coords=[x*u"Å" for x in c])))
                h = 1e-4
                f_fd = map(eachindex(crd)) do a
                    SVector{3,Float64}(ntuple(3) do d
                        cp = copy(crd); cm = copy(crd)
                        cp[a] = setindex(cp[a], cp[a][d] + h, d)
                        cm[a] = setindex(cm[a], cm[a][d] - h, d)
                        -(E(cp) - E(cm)) / (2h)
                    end)
                end

                @test maximum(maximum(abs.(f_ka[i]  .- f_ref[i])) for i in eachindex(f_ka)) < 3e-3
                @test maximum(maximum(abs.(f_ka[i]  .- f_fd[i]))  for i in eachindex(f_ka)) < 1e-2
                @test maximum(maximum(abs.(f_sys[i] .- f_ka[i]))  for i in eachindex(f_ka)) < 1e-4
                @test isapprox(sum(f_ka), zeros(SVector{3}); atol=1e-6)   # Newton's 3rd law
                println("Test19 $jf: max|KA-TorchANI|=",
                    maximum(maximum(abs.(f_ka[i] .- f_ref[i])) for i in eachindex(f_ka)),
                    " max|KA-FD|=",
                    maximum(maximum(abs.(f_ka[i] .- f_fd[i])) for i in eachindex(f_ka)),
                    " max|forces(sys)-KA|=",
                    maximum(maximum(abs.(f_sys[i] .- f_ka[i])) for i in eachindex(f_ka)),
                    " |ΣF|=", maximum(abs.(sum(f_ka))))
            end
        end
    end
end
